//! Hmc-gitmine — `ga_minimal_context` GT rule for M3 bench.
//!
//! ## Anti-tautology policy
//! This rule does NOT import `ga_query::{dead_code, callers, rename_safety,
//! architecture, risk, minimal_context}` analysis types. The expected sets
//! come from `benches/uc-impact/ground-truth.json` (M1+M2 git-mining
//! dataset, generated by `scripts/mine-fix-commits.ts` from real upstream
//! fix commits — no LLM, no runtime trace, no engine introspection).
//! See spec §C1.
//!
//! ## Source dataset
//! `benches/uc-impact/ground-truth.json` — 209 tasks across 12 repos, with
//! `base_commit` per task for fixture pinning + `split: dev/test` for
//! sandbox vs gate separation.
//!
//! ## Why not reuse `m2_ground_truth::M2GroundTruth`?
//! Per user direction (2026-04-28): keep M1/M2/M3 independent. M2 owning
//! the loader would couple M3's gate to M2's schema-evolution decisions.
//! This file ships its own ~30-line JSON parser to stay decoupled. The
//! schema is read-only (we never write the dataset back), so divergence
//! risk = "if M2 adds a field we don't read, we just ignore it" —
//! acceptable.

use super::{GeneratedTask, GtRule};
use crate::BenchError;
use ga_index::Store;
use serde::{Deserialize, Serialize};
use serde_json::json;
use std::path::{Path, PathBuf};

/// Default ground-truth file path (relative to workspace root).
const GT_REL: &str = "benches/uc-impact/ground-truth.json";

#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "lowercase")]
pub enum Split {
    Dev,
    Test,
}

impl Split {
    fn as_str(self) -> &'static str {
        match self {
            Self::Dev => "dev",
            Self::Test => "test",
        }
    }
}

/// Minimal task shape we read from `ground-truth.json`. `serde(default)`
/// on optional-ish fields keeps us tolerant of M2 schema additions.
#[derive(Debug, Clone, Deserialize)]
struct GtRow {
    task_id: String,
    repo: String,
    #[serde(default)]
    base_commit: String,
    #[serde(default)]
    seed_file: String,
    #[serde(default)]
    seed_symbol: String,
    #[serde(default)]
    expected_files: Vec<String>,
    #[serde(default)]
    expected_tests: Vec<String>,
    #[serde(default)]
    should_touch_files: Vec<String>,
    #[serde(default = "default_split")]
    split: String,
}

fn default_split() -> String {
    "test".to_string()
}

#[derive(Debug, Clone, Deserialize)]
struct GtFile {
    tasks: Vec<GtRow>,
}

pub struct HmcGitmine {
    /// Filter to a single repo (`Some("django")` keeps only `repo=="django"`).
    /// `None` = all repos.
    pub fixture: Option<String>,
    /// Score on this split only. Default = `Test` (gate); use `Dev` for
    /// sandbox / tuning runs that should NEVER feed back into the spec
    /// target (Codex round 3 review — avoid optimize-on-test-set).
    pub split: Split,
    /// Optional explicit dataset path. `None` ⇒ walk up from CWD looking
    /// for `benches/uc-impact/ground-truth.json`.
    pub gt_path: Option<PathBuf>,
}

impl Default for HmcGitmine {
    fn default() -> Self {
        Self {
            fixture: None,
            split: Split::Test,
            gt_path: None,
        }
    }
}

impl HmcGitmine {
    pub fn for_fixture(name: impl Into<String>) -> Self {
        Self {
            fixture: Some(name.into()),
            ..Self::default()
        }
    }

    pub fn with_split(mut self, split: Split) -> Self {
        self.split = split;
        self
    }

    pub fn with_gt_path(mut self, path: PathBuf) -> Self {
        self.gt_path = Some(path);
        self
    }
}

impl GtRule for HmcGitmine {
    fn id(&self) -> &str {
        "Hmc-gitmine"
    }
    fn uc(&self) -> &str {
        "minimal_context"
    }
    fn policy_bias(&self) -> &str {
        "GT from benches/uc-impact/ground-truth.json (git-mining of real upstream \
         fix commits — no LLM, no runtime trace). File-level recall measured against \
         expected_files; minimal_context is fundamentally narrower than impact, so \
         absolute scores are lower than M2 impact numbers on the same dataset. \
         Default scoring split = `test`. Pin per-task base_commit via M2's existing \
         pin_commits infrastructure (allowed shared primitive — infra coupling, not \
         GT semantics)."
    }

    fn scan(&self, _store: &Store, _fixture_dir: &Path) -> Result<Vec<GeneratedTask>, BenchError> {
        let path = match &self.gt_path {
            Some(p) => p.clone(),
            None => locate_gt()?,
        };
        let body = std::fs::read_to_string(&path).map_err(|e| {
            BenchError::Other(anyhow::anyhow!(
                "read ground-truth.json at {}: {e}",
                path.display()
            ))
        })?;
        let file: GtFile = serde_json::from_str(&body).map_err(|e| {
            BenchError::Other(anyhow::anyhow!(
                "parse ground-truth.json at {}: {e}",
                path.display()
            ))
        })?;

        let want_split = self.split.as_str();
        let mut out: Vec<GeneratedTask> = file
            .tasks
            .into_iter()
            .filter(|r| {
                if let Some(want) = self.fixture.as_deref() {
                    if r.repo != want {
                        return false;
                    }
                }
                r.split == want_split
            })
            .map(|r| GeneratedTask {
                task_id: r.task_id.clone(),
                query: json!({
                    "symbol": r.seed_symbol,
                    "repo": r.repo,
                    "__base_commit": r.base_commit,
                    "__seed_file": r.seed_file,
                    "__expected_tests": r.expected_tests,
                    "__should_touch_files": r.should_touch_files,
                    "__split": r.split,
                }),
                expected: r.expected_files,
                rule: "Hmc-gitmine".to_string(),
                rationale: format!(
                    "ground-truth.json task `{}` (repo `{}`, split `{}`); \
                     expected = expected_files",
                    r.task_id, r.repo, r.split
                ),
            })
            .collect();

        // Deterministic order — Codex round 1 feedback. Reproducibility +
        // stable diffs in leaderboard markdown across runs.
        out.sort_by(|a, b| a.task_id.cmp(&b.task_id));
        Ok(out)
    }
}

fn locate_gt() -> Result<PathBuf, BenchError> {
    if let Ok(v) = std::env::var("GA_BENCH_GT_PATH") {
        return Ok(PathBuf::from(v));
    }
    let mut cur: PathBuf = std::env::current_dir()?;
    for _ in 0..6 {
        let candidate = cur.join(GT_REL);
        if candidate.is_file() {
            return Ok(candidate);
        }
        if !cur.pop() {
            break;
        }
    }
    Err(BenchError::Other(anyhow::anyhow!(
        "could not locate {GT_REL} from CWD; set GA_BENCH_GT_PATH to override"
    )))
}
